const PORT_CTRL_FEEDBACK: usize = 10;
const PORT_CTRL_DAMP: usize = 11;
const PORT_CTRL_REV: usize = 12;
const PORT_CTRL_SUBD: usize = 13;
const PORT_CTRL_ES: usize = 14;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_REVERB.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("wetdry", "Wet/Dry", None, Some(67.0), 0.0, 127.0, 1.0, ParameterUnit::None),
            float_parameter("pan", "Panning", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
            float_parameter("delay", "TEMPO", None, Some(128.0), 1.0, 600.0, 1.0, ParameterUnit::None),
            float_parameter("lr_delay", "Left/Right Delay Offset", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
            float_parameter("angle", "Angle", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
            float_parameter("feedback", "Feedback", None, Some(59.0), 0.0, 127.0, 1.0, ParameterUnit::None),
            float_parameter("damp", "Damping", None, Some(0.0), 0.0, 127.0, 1.0, ParameterUnit::None),
            float_parameter("rev", "Reverse", None, Some(0.0), 0.0, 127.0, 1.0, ParameterUnit::None),
            float_parameter("subd", "Subdivision", None, Some(1.0), 1.0, 6.0, 0.01, ParameterUnit::None),
            float_parameter("es", "Extra Stereo", None, Some(0.0), 0.0, 127.0, 1.0, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let wetdry = required_f32(params, "wetdry").map_err(anyhow::Error::msg)?;
    let pan = required_f32(params, "pan").map_err(anyhow::Error::msg)?;
    let delay = required_f32(params, "delay").map_err(anyhow::Error::msg)?;
    let lr_delay = required_f32(params, "lr_delay").map_err(anyhow::Error::msg)?;
    let angle = required_f32(params, "angle").map_err(anyhow::Error::msg)?;
    let feedback = required_f32(params, "feedback").map_err(anyhow::Error::msg)?;
    let damp = required_f32(params, "damp").map_err(anyhow::Error::msg)?;
    let rev = required_f32(params, "rev").map_err(anyhow::Error::msg)?;
    let subd = required_f32(params, "subd").map_err(anyhow::Error::msg)?;
    let es = required_f32(params, "es").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_WETDRY, wetdry),
        (PORT_CTRL_PAN, pan),
        (PORT_CTRL_DELAY, delay),
        (PORT_CTRL_LR_DELAY, lr_delay),
        (PORT_CTRL_ANGLE, angle),
        (PORT_CTRL_FEEDBACK, feedback),
        (PORT_CTRL_DAMP, damp),
        (PORT_CTRL_REV, rev),
        (PORT_CTRL_SUBD, subd),
        (PORT_CTRL_ES, es),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: ReverbModelDefinition = ReverbModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: ReverbBackendKind::Lv2, schema, build,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};
